var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여긴…….","JPN":"ここは……","ENG":"Where are we?","TWN":"這裡是……"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"내성이로군요.","JPN":"内郭ですね。","ENG":"The inner castle, it seems.","TWN":"原來是城內。"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"주변을 관찰해 보세요. 여기도 알렌 선생님의 집에 펼쳐져 있던 성벽 도시와 흡사하네요.","JPN":"周りを見てください。アレン先生の家から繋がっていた城郭都市に似ていますね。","ENG":"Look around you. It's similar to the walled city at Mr. Birmingham's place.","TWN":"你們看看周圍，是不是很類似那時候艾倫老師家的景象。"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"규모가 더 큰 걸 봐서는 이쪽이 원본 같아요.","JPN":"規模がもっと大きいのを見るに、こちらが元のようです。","ENG":"Considering the bigger scale, this must be the original.","TWN":"只是規模更大，看來這裡應該才是真的。"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이 도시의 지배자가 있다면 바로 저 안에 있을 거예요.","JPN":"この都市の支配者がいるならあの中にいるはずです。","ENG":"The city's ruler should be somewhere in there.","TWN":"這個城市的支配者應該就在那裡面。"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"궁전 지하는 외부의 접근이 어려우니 사람을 감금해 두기도 적절하겠죠.","JPN":"宮殿の地下は外部からの侵入が難しいので、人を監禁しておくのに適切でしょう。","ENG":"The dungeons of the castle would be perfect to keep intruders out and prisoners in.","TWN":"宮殿的地下城難以與外界接觸，應該很適合用來監禁人。"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"제대로 찾아온 것 같긴 한데…….","JPN":"ここで間違いないようだけど……","ENG":"This does look like the right place…","TWN":"好像是這裡沒錯……"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"어때, 유미나? 뭔가 느껴져?","JPN":"どう、ミナ？　何か感じる？","ENG":"Well, Mina? Can you feel anything?","TWN":"如何？劉米娜？有什麼反應嗎？"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응. 이 안으로 선배의 힘이 이어져 있어.","JPN":"うん。この中に先輩の力が繋がってる。","ENG":"Yeah. The signature of Shiyoon's power is coming from there.","TWN":"嗯，前輩就在那裡面！"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"서두르자. 여기 올 때 느꼈던 것보다 힘이 더 약해졌어.","JPN":"急ごう。ここに来る時感じた力より弱まってる。","ENG":"Let's hurry though. The signature is weaker than when we first got here.","TWN":"動作快！前輩的力量似乎比我們來的時候更弱了。"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"마치…… 뭔가가 선배의 힘을 빨아들이고 있는 것처럼.","JPN":"まるで……何かが先輩の力を吸い込んでいるみたい。","ENG":"It's as if… something is sucking away his power.","TWN":"好像……有什麼東西正在吸取前輩的力量！"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"좋아. 그럼 어서…….","JPN":"よし。それじゃあ早く……","ENG":"Okay, then. Let's hurry before-","TWN":"好！快……"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"앗, 따거!","JPN":"痛っ！","ENG":"Ow, that stings!","TWN":"噢！好痛！"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"왜 그래? 갑자기?","JPN":"急にどうしたの？","ENG":"Huh? What's wrong?","TWN":"怎麼突然這樣？"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"역장이 가로막고 있어. 역시 쉽게 들여보내 주진 않네.","JPN":"力場で遮られている。やっぱり簡単には入れてくれなさそう。","ENG":"There's a force field blocking the way. Of course they wouldn't make this easy.","TWN":"力場把路擋住了，果然沒這麼容易的事！"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼 힘으로 부수고 들어가면 어때?","JPN":"じゃあ、壊して入るのはどう？","ENG":"Why don't we just smash our way through?","TWN":"那還是靠蠻力硬闖如何？"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"무식한 방법이지만 시도해봐서 나쁠 건 없겠지.","JPN":"単純な方法だけど、試してみて損はないだろうね。","ENG":"It's not very nuanced, but it's worth a try I guess.","TWN":"雖然有點魯莽，但試試看也不會少塊肉。"},"stage":{"bg":"CASTLE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};